/**
 * Tool Batch Observer
 * Hook: PostToolBatch (CC 2.1.208)
 *
 * Fires when a batch of parallel tool calls resolves. OBSERVER ONLY (P3-A3):
 * never blocks, never modifies — emits one compact telemetry line (batch
 * size + tool-name histogram sample) so we learn the live payload shape and
 * real-world parallelism.
 *
 * Input is UNTRUSTED and the payload shape is unverified against live CC:
 * the batch array may be absent, non-array, or huge. Tool names are
 * sanitized to a safe charset, individually capped, and at most
 * MAX_NAMES_LOGGED are ever logged. Tool inputs/outputs are never logged.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, logHook } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'posttool/tool-batch-observer';

/** Cap on how many tool names one telemetry line may carry. */
const MAX_NAMES_LOGGED = 8;
/** Cap on a single sanitized tool-name token. */
const MAX_NAME_LEN = 32;

/** First array found under the plausible batch keys; [] when none. */
function batchArray(input: HookInput): unknown[] {
  const rec = input as unknown as Record<string, unknown>;
  for (const key of ['tool_calls', 'batch', 'tools', 'results']) {
    const v = rec[key];
    if (Array.isArray(v)) return v;
  }
  return [];
}

/** Sanitized tool name from one untrusted batch item ('?' when unreadable). */
function toolNameOf(item: unknown): string {
  if (typeof item !== 'object' || item === null) return '?';
  const rec = item as Record<string, unknown>;
  const raw = rec.tool_name ?? rec.toolName ?? rec.name;
  if (typeof raw !== 'string' || raw.length === 0) return '?';
  const clean = raw.replace(/[^\w.-]/g, '');
  return clean.slice(0, MAX_NAME_LEN) || '?';
}

export async function toolBatchObserver(
  input: HookInput,
  _ctx: HookContext = NOOP_CTX,
): Promise<HookResult> {
  try {
    const batch = batchArray(input);
    const names = batch.slice(0, MAX_NAMES_LOGGED).map(toolNameOf);
    const suffix = batch.length > MAX_NAMES_LOGGED ? `,+${batch.length - MAX_NAMES_LOGGED}` : '';

    logHook(
      HOOK_NAME,
      `batch resolved size=${batch.length} tools=[${names.join(',')}${suffix}]`,
      'info',
    );
  } catch {
    // Observer only — never let telemetry failures surface to CC
  }
  return outputSilentSuccess();
}
